4"></td><td class="xl151964"></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="64" style="height: 48pt;"><td height="64" class="xl151964" style="height: 48pt;"></td><td class="xl711964">　</td><td colspan="4" class="xl791964" width="540" style="width: 406pt;">기업은 종업원 500명에게 각각
  주식선택권 100개를 부여하였다. 각 주식선택권은 종업원이 앞으로 3년간 근무할 것을 조건으로 한다. 부여일 현재 주식선택권의 단위당
  공정가치는 15원으로 추정되었다.<span>&nbsp;</span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl151964" style="height: 15.6pt;"></td><td class="xl711964">　</td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="42" style="height: 31.95pt;"><td height="42" class="xl151964" style="height: 31.95pt;"></td><td class="xl711964">　</td><td colspan="4" class="xl791964" width="540" style="width: 406pt;">가중평균확률에 기초하여, 기업은
  종업원 중 20%가 부여일로부터 3년 이내에 퇴사하여 주식선택권을 상실할 것으로 추정하였다.</td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl151964" style="height: 15.6pt;"></td><td class="xl711964">　</td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl151964" style="height: 15.6pt;"></td><td class="xl711964">　</td><td class="xl731964" colspan="2">요구사항의 적용</td><td class="xl151964"></td><td class="xl151964"></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl151964" style="height: 15.6pt;"></td><td class="xl711964">　</td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl151964" style="height: 15.6pt;"></td><td class="xl711964">　</td><td colspan="4" class="xl741964" width="540" style="width: 406pt;"><span lang="EN-US">(상황
  1)</span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="42" style="height: 31.95pt;"><td height="42" class="xl151964" style="height: 31.95pt;"></td><td class="xl711964">　</td><td colspan="4" class="xl791964" width="540" style="width: 406pt;">실제 결과가 추정과 일치한다면
  기업이 가득기간에 주식선택권의 대가로 제공받는 근무용역에 대해 인식할 금액은 다음과 같다.<span>&nbsp;</span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl151964" style="height: 15.6pt;"></td><td class="xl711964">　</td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl751964"><span lang="EN-US">(단위: 원)</span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="32" style="height: 24pt;"><td height="32" class="xl151964" style="height: 24pt;"></td><td class="xl711964">　</td><td class="xl651964">연도</td><td class="xl651964" style="border-left: none;">계산</td><td class="xl651964" style="border-left: none;">당기 보상비용</td><td class="xl651964" style="border-left: none;">누적 보상비용</td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="42" style="height: 31.95pt;"><td height="42" class="xl151964" style="height: 31.95pt;"></td><td class="xl711964">　</td><td class="xl651964" style="border-top: none;"><span lang="EN-US">1</span></td><td class="xl661964" style="border-top: none; border-left: none;"><span lang="EN-US">50,000개×80%×15원×1/3</span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">200,000 </span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">200,000 </span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="42" style="height: 31.95pt;"><td height="42" class="xl151964" style="height: 31.95pt;"></td><td class="xl711964">　</td><td class="xl651964" style="border-top: none;"><span lang="EN-US">2</span></td><td class="xl661964" style="border-top: none; border-left: none;"><span lang="EN-US">(50,000개×80%×15원×2/3)-200,000원</span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">200,000 </span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">400,000 </span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="42" style="height: 31.95pt;"><td height="42" class="xl151964" style="height: 31.95pt;"></td><td class="xl711964">　</td><td class="xl651964" style="border-top: none;"><span lang="EN-US">3</span></td><td class="xl661964" style="border-top: none; border-left: none;"><span lang="EN-US">(50,000개×80%×15원×3/3)-400,000원</span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">200,000 </span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">600,000 </span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl151964" style="height: 15.6pt;"></td><td class="xl711964">　</td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl151964" style="height: 15.6pt;"></td><td class="xl711964">　</td><td colspan="4" class="xl741964" width="540" style="width: 406pt;"><span lang="EN-US">(상황
  2)</span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="128" style="height: 96pt;"><td height="128" class="xl151964" style="height: 96pt;"></td><td class="xl711964">　</td><td colspan="4" class="xl791964" width="540" style="width: 406pt;"><span lang="EN-US">1차년도
  중에 20명이 퇴사하였고, 기업은 가득기간(3년)에 퇴사할 것으로 기대되는 종업원의 추정비율을 20%(100명)에서 15%(75명)로
  수정하였다. 2차년도에 22명이 더 퇴사하였고, 기업은 가득기간(3년) 전체에 걸쳐 퇴사할 것으로 기대되는 종업원의 추정비율을 다시
  15%에서 12%(60명)로 변경하였다. 3차년도에는 15명이 더 퇴사하였다. 결국 3차년도 말 현재 총 57명이 퇴사하여 주식선택권을
  상실하였고 총 44,300개(443명×100개)의 주식선택권이 가득되었다.</span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="21" style="height: 15.6pt;"><td height="21" class="xl151964" style="height: 15.6pt;"></td><td class="xl711964">　</td><td class="xl151964"></td><td class="xl151964"></td><td class="xl151964"></td><td class="xl751964"><span lang="EN-US">(단위: 원)</span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="32" style="height: 24pt;"><td height="32" class="xl151964" style="height: 24pt;"></td><td class="xl711964">　</td><td class="xl651964">연도</td><td class="xl651964" style="border-left: none;">계산</td><td class="xl651964" style="border-left: none;">당기 보상비용</td><td class="xl651964" style="border-left: none;">누적 보상비용</td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="42" style="height: 31.95pt;"><td height="42" class="xl151964" style="height: 31.95pt;"></td><td class="xl711964">　</td><td class="xl651964" style="border-top: none;"><span lang="EN-US">1</span></td><td class="xl661964" style="border-top: none; border-left: none;"><span lang="EN-US">50,000개×85%×15원×1/3</span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">212,500 </span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">212,500 </span></td><td class="xl721964">　</td><td class="xl151964"></td></tr><tr height="42" style="height: 31.95pt;"><td height="42" class="xl151964" style="height: 31.95pt;"></td><td class="xl711964">　</td><td class="xl651964" style="border-top: none;"><span lang="EN-US">2</span></td><td class="xl661964" style="border-top: none; border-left: none;"><span lang="EN-US">(50,000개×88%×15원×2/3)-212,500원</span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">227,500 </span></td><td class="xl671964" align="right" style="border-top: none; border-left: none;"><span lang="EN-US">